const payload = $json?.workflowRun ?? $json?.data?.workflowRun ?? null;
if (!payload) {
  throw new Error('Workflow run payload missing from API response.');
}
const metadata = {};
if (payload.input && typeof payload.input === 'object') {
  if (payload.input.metadata && typeof payload.input.metadata === 'object') {
    Object.assign(metadata, payload.input.metadata);
  }
  if (payload.input.turn && typeof payload.input.turn === 'object' && payload.input.turn.metadata && typeof payload.input.turn.metadata === 'object') {
    Object.assign(metadata, payload.input.turn.metadata);
  }
  if (payload.input.projectSlug && typeof payload.input.projectSlug === 'string' && !metadata.projectSlug) {
    metadata.projectSlug = payload.input.projectSlug;
  }
}
if (!metadata.projectSlug && typeof payload.projectId === 'string') {
  metadata.projectSlug = payload.projectId;
}
const videoOutput = payload.output?.video_generation ?? {};
const normalized = {
  ...payload,
  metadata,
  created_at: payload.createdAt ?? null,
  updated_at: payload.updatedAt ?? null,
  result: videoOutput.videoUrl ?? payload.result ?? null,
  video_output: videoOutput
};
return [{ json: normalized }];

// Handle workflow error and preserve state
const errorData = $json ?? {};

// Try to get runId from various sources
let runId = null;
try {
  runId = $('Get a row').item?.json?.id ?? $('When Called by Generate Video').item?.json?.runId ?? null;
} catch (e) {
  console.log('Could not extract runId from executed nodes');
}

// If we still don't have runId, we can't update the workflow
if (!runId) {
  console.error('Unable to determine runId for error handling');
  return [{ json: { error: 'No runId available to update workflow run', errorData } }];
}

// Get the workflow run to preserve prior outputs
let run = {};
try {
  run = $('Get a row').item?.json ?? {};
} catch (e) {
  console.log('Could not get workflow run data');
}

const stages = run.stages ?? {};
const clone = (value) => (value && typeof value === 'object' ? { ...value } : {});

// Set prior stages as completed
const ideaStage = clone(stages.idea_generation);
if (!ideaStage.status) {
  ideaStage.status = 'completed';
}

const screenplayStage = clone(stages.screenplay);
if (!screenplayStage.status) {
  screenplayStage.status = 'completed';
}

const videoStage = clone(stages.video_generation);
if (!videoStage.status) {
  videoStage.status = 'completed';
}

// Mark publishing stage failed
const publishingStage = {
  ...clone(stages.publishing),
  status: 'failed',
  error: {
    message: errorData.error?.message ?? 'Google Drive upload failed.',
    stack: errorData.error?.stack ?? null,
    lastNode: errorData.execution?.lastNodeExecuted ?? null,
    timestamp: new Date().toISOString()
  }
};

return {
  json: {
    runId,
    status: 'failed',
    currentStage: 'publishing',
    stages: {
      idea_generation: ideaStage,
      screenplay: screenplayStage,
      video_generation: videoStage,
      publishing: publishingStage
    },
    output: {
      ...(run.output ?? {}),
      // CRITICAL: Preserve ALL prior outputs
      idea_generation: run.output?.idea_generation ?? {},
      screenplay: run.output?.screenplay ?? {},
      video_generation: run.output?.video_generation ?? {},
      publishing: {
        ...(run.output?.publishing ?? {}),
        error: {
          message: errorData.error?.message ?? 'Google Drive upload failed.',
          timestamp: new Date().toISOString()
        }
      }
    }
  }
};
